'use strict';

// MODULES //

import isColumnMajor from '@stdlib/ndarray/base/assert/is-column-major-string';
import isLayout from './../../../../base/assert/is-layout';
import stride2offset from '@stdlib/strided/base/stride2offset';
import max from '@stdlib/math/base/special/fast/max';
import format from '@stdlib/string/format';
import base from './base.js';


// MAIN //

/**
* Generates a double-precision floating-point Vandermonde matrix.
*
* @param {string} order - storage layout
* @param {integer} mode - mode indicating whether to generate increasing or decreasing powers
* @param {NonNegativeInteger} M - number of rows in `out`
* @param {NonNegativeInteger} N - number of columns in `out`
* @param {Float64Array} x - input array
* @param {integer} strideX - stride length for `x`
* @param {Float64Array} out - output matrix
* @param {PositiveInteger} ldo - stride between successive contiguous vectors of the matrix `out` (a.k.a., leading dimension of the matrix `out`)
* @throws {TypeError} first argument must be a valid order
* @throws {RangeError} third argument must be a nonnegative integer
* @throws {RangeError} fourth argument must be a nonnegative integer
* @throws {RangeError} eighth argument must be a valid stride
* @returns {Float64Array} output matrix
*
* @example
* import Float64Array from '@stdlib/array/float64';
*
* var x = new Float64Array( [ 1.0, 2.0, 3.0 ] );
* var out = new Float64Array( 9 );
*
* dvander( 'row-major', -1, 3, 3, x, 1, out, 3 );
* // out => <Float64Array>[ 1.0, 1.0, 1.0, 4.0, 2.0, 1.0, 9.0, 3.0, 1.0 ]
*/
function dvander( order, mode, M, N, x, strideX, out, ldo ) {
	var iscm;
	var sa1;
	var sa2;
	var ox;
	var k;

	if ( !isLayout( order ) ) {
		throw new TypeError( format( 'invalid argument. First argument must be a valid order. Value: `%s`.', order ) );
	}
	if ( M < 0 ) {
		throw new RangeError( format( 'invalid argument. Third argument must be a nonnegative integer. Value: `%d`.', M ) );
	}
	if ( N < 0 ) {
		throw new RangeError( format( 'invalid argument. Fourth argument must be a nonnegative integer. Value: `%d`.', N ) );
	}
	iscm = isColumnMajor( order );
	if ( iscm ) {
		k = M;
	} else {
		k = N;
	}
	if ( ldo < max( 1, k ) ) {
		throw new RangeError( format( 'invalid argument. Eighth argument must be greater than or equal to max(1,%d). Value: `%d`.', k, ldo ) );
	}
	if ( M === 0 || N === 0 ) {
		return out;
	}
	ox = stride2offset( M, strideX );
	if ( iscm ) {
		sa1 = 1;
		sa2 = ldo;
	} else { // order === 'row-major'
		sa1 = ldo;
		sa2 = 1;
	}
	return base( mode, M, N, x, strideX, ox, out, sa1, sa2, 0 );
}


// EXPORTS //

export default dvander;
